% This code was used for trial alignment by SVM within sessions and sequence
% extraction. save to sxx_SVM.mat and sxx_SVM_wake.mat, BUT the saved mat
% were not used for further analysis. sxx_SVM2.mat and sxx_SVM_wake2.mat
% were used, see GPR_find_seq_in_all_trials.m
%% prepare data
clc;
clear;
addpath(genpath('~/code'));
subj='s74';

filepath='~/';
load(strcat(filepath,'start_stop_SVM.mat'));
load(strcat(filepath,'update_brain_region_for_fig1.mat'),strcat(subj,'_cluster_channel_br'));
load(strcat(filepath,'update_brain_region_for_fig1.mat'),strcat(subj,'_cluster_channel_name'));
eval(strcat('tmp_cluster_channel_br=',subj,'_cluster_channel_br;'));
eval(strcat('tmp_cluster_channel_name=',subj,'_cluster_channel_name;'));


matfile=strcat(filepath,strcat(subj,'_postprocess_0.5s.mat'));
load(matfile, strcat(subj,'_cluster_spike_good'));
eval(strcat('temp_spike=',subj,'_cluster_spike_good;'));
load(matfile, 'start_time'); 
load(matfile, 'labels');

fr_t=0.025;%freq_time s
start=start_stop_SVM(find(start_stop_SVM(:,1)==str2double(subj(2:end))),2)*3600; % EEG start hour *
stop=start_stop_SVM(find(start_stop_SVM(:,1)==str2double(subj(2:end))),3)*3600; % stop
temp_spike_freq=temp_spike(:,round(start-start_time)*1000+1:round(stop-start_time)*1000);
temp_spike_freq=temp_spike_freq(:,1:round(size(temp_spike_freq,2)/(fr_t/0.001))*(fr_t/0.001))';
temp_spike_freq=full(temp_spike_freq);
temp_spike_freq=reshape(temp_spike_freq,(fr_t/0.001),[],size(temp_spike_freq,2));
temp_spike_freq=squeeze(sum(temp_spike_freq,1))';


labels_i=labels(round(start/2.5)+1:round(stop/2.5)+1);
temp_labels=repmat(labels_i,[1 100]);
temp_labels=reshape(temp_labels',[],1);
temp_labels=temp_labels(1:size(temp_spike_freq,2));
table_states=stable_states(temp_labels,0.025);


%find long WN(2to3) NW(3to2)
tmp_dif=diff(table_states(:,1));
idx_23=find(tmp_dif==3); %3 WN -3 NW
idx_long23=[];
for  i = 1:length(idx_23)
    tmp_idx=idx_23(i);
    if table_states(tmp_idx,2)>=400 && table_states(tmp_idx+1,2)>=400
        idx_long23=[idx_long23;tmp_idx];
    end
end

idx_medium23=[];
for  i = 1:length(idx_23)
    tmp_idx=idx_23(i);
    if table_states(tmp_idx,2)>=200 && table_states(tmp_idx+1,2)>=200
        idx_medium23=[idx_medium23;tmp_idx];
    end
end

%
presence_ratio=presence_ratio_state(temp_spike_freq,temp_labels);
idx_good_presence=find(sum(presence_ratio>=0.9,2)>0);
temp_spike_freq=temp_spike_freq(idx_good_presence,:);
tmp_cluster_channel_br=tmp_cluster_channel_br(idx_good_presence,:);
tmp_cluster_channel_name=tmp_cluster_channel_name(:,idx_good_presence);

%% part 1 training
% directly use z-scored raw data...........................................
temp_spike_freq_slid_1=movmean(temp_spike_freq,25,2); % sliding win = 0.625 s: better for predict transition time point
temp_spike_freq_slid_z1=zscore(temp_spike_freq_slid_1,0,2);
% prepare traing data
labels_23_1=[];
spike_freq_23_1=[];
t_stable=0.5;
for i = 1:length(idx_medium23)
    tmp_idx=idx_medium23(i);
    half_win1=table_states(tmp_idx,2)*t_stable/2;
    tmp_spike_freq1=temp_spike_freq_slid_z1(:,table_states(tmp_idx,4)+half_win1:table_states(tmp_idx,5)-half_win1);
    tmp_labels1=temp_labels(table_states(tmp_idx,4)+half_win1:table_states(tmp_idx,5)-half_win1);
    
    tmp_idx=idx_medium23(i)+1;
    half_win2=table_states(tmp_idx,2)*t_stable/2;
    tmp_spike_freq2=temp_spike_freq_slid_z1(:,table_states(tmp_idx,4)+half_win2:table_states(tmp_idx,5)-half_win2);
    tmp_labels2=temp_labels(table_states(tmp_idx,4)+half_win2:table_states(tmp_idx,5)-half_win2);
    
    sample_num=100;
    rng(1);
    randomOrder = randperm(size(tmp_spike_freq1,2));
    randomOrder = randomOrder(1:sample_num);
    tmp_spike_freq1=tmp_spike_freq1(:,randomOrder);
    tmp_labels1=tmp_labels1(randomOrder);

    randomOrder = randperm(size(tmp_spike_freq2,2));
    randomOrder = randomOrder(1:sample_num);
    tmp_spike_freq2=tmp_spike_freq2(:,randomOrder);
    tmp_labels2=tmp_labels2(randomOrder);

    tmp_spike_trial=[tmp_spike_freq1,tmp_spike_freq2];

    spike_freq_23_1=[spike_freq_23_1,tmp_spike_trial];
    labels_23_1=[labels_23_1;tmp_labels1;tmp_labels2];
end


% prepare test data
num_neurons=size(temp_spike_freq,1);
trial_num=length(idx_medium23);
spike_freq_2to3_1=zeros(num_neurons,400,trial_num);
for i = 1:trial_num                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
    tmp_idx=idx_medium23(i)+1;
    half_win3=5*1000/25;
    tmp_spike_freq=temp_spike_freq_slid_z1(:,table_states(tmp_idx,4)-half_win3:table_states(tmp_idx,4)+half_win3-1);

    tmp_labels=temp_labels(table_states(tmp_idx,4)-half_win3:table_states(tmp_idx,4)+half_win3-1);
    spike_freq_2to3_1(:,:,i)=tmp_spike_freq;
    labels_2to3_1=tmp_labels;
end

%%
% training SVM model for predict trans time point..........................
% data partition for 5-fold
tmp_data=spike_freq_23_1;
numFolds=5;
Foldsize=size(tmp_data,2)/numFolds;
dataCellArray = mat2cell(tmp_data, size(tmp_data, 1), repmat(Foldsize, 1, numFolds));

regenerated_data1={};
for i =1:numFolds
    remaining = dataCellArray([1:i-1, i+1:end]);
    valid_dataset=dataCellArray{i};
    regenerated_data1{1,i} = cat(2, remaining{:});
    regenerated_data1{2,i} = [labels_23_1(1 : (i-1)*Foldsize); labels_23_1(i*Foldsize + 1 : end)];
    regenerated_data1{3,i} = valid_dataset;
    regenerated_data1{4,i} = [labels_23_1((i-1)*Foldsize+1 : i*Foldsize)];
end

% model training
SVM_acc_brain=[];
SVM_brain={};
pred_state_f={};
parfor f = 1:numFolds
    %progressbar(f,numFolds)
    tmp_br_data=regenerated_data1{1,f};    
    tmp_labels=regenerated_data1{2,f};
    tmp_valid_data=regenerated_data1{3,f};
    tmp_valid_label=regenerated_data1{4,f};
    rng(1);      % for reproduce 'KernelScale', 'auto',
    classificationSVM = fitcsvm(...
        tmp_br_data', ...
        tmp_labels, ...
        'Standardize', true, ...
        'BoxConstraint', 1, ... % C
        'KernelFunction', 'linear', ...
        'KernelScale', 'auto', ... %gammar
        'ClassNames', [3; 2]);

    posteriorSVM = fitPosterior(classificationSVM);
    SVM_brain{f} = posteriorSVM;

    pred_state = predict(classificationSVM,tmp_valid_data');
    pred_state_f{f}=pred_state;
    SVM_acc_brain(f)=sum(pred_state==tmp_valid_label)/length(tmp_valid_label)*100; 
end

% predict trans time point by all neurons
temp_data=spike_freq_2to3_1;
acc_brain=[];
for t=1:size(temp_data,3)
    %progressbar(t,size(temp_data,3))
    tmp_br_data=squeeze(temp_data(:,:,t));
    parfor f = 1:numFolds
        temp_svm=SVM_brain{f};
        [pred_state,pred_score] = predict(temp_svm,tmp_br_data');
        acc=length(find(pred_state-labels_2to3_1==0))/length(pred_state)*100;

        pred_state_1(:,t,f)=pred_state;
        pred_score_1(:,:,t,f)=pred_score;
        acc_brain(t,f)=acc;
    end
end

% choose good model
temp_score=squeeze(mean(pred_score_1,4));
idx_acc_good=find(mean(acc_brain,2)>=70);
temp_score=temp_score(:,1,idx_acc_good);
idx_medium23_good_model=idx_medium23(idx_acc_good);
score_trial_average=temp_score;
%....................manual check to get t_points..........................
t_points_brain=t_points(:,1);
tmp_idx=find(~isnan(t_points_brain));
idx_medium23_good_curve=idx_medium23_good_model(tmp_idx);
score_good_curve=temp_score(:,1,tmp_idx);

trans_time=t_points_brain(tmp_idx)';
offset=trans_time-200;
table_states_corr=table_states;
table_states_corr(idx_medium23_good_curve+1,4)=table_states_corr(idx_medium23_good_curve+1,4)+offset';
table_states_corr(idx_medium23_good_curve,5)=table_states_corr(idx_medium23_good_curve+1,4)-1;


%% part 2 correction
% prepare corrected test data
trial_num=length(idx_medium23_good_curve);
spike_freq_2to3_2=zeros(num_neurons,400,trial_num);
for i = 1:trial_num                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
    tmp_idx=idx_medium23_good_curve(i)+1;
    half_win3=5*1000/25;
    tmp_spike_freq=temp_spike_freq_slid_z1(:,table_states_corr(tmp_idx,4)-half_win3:table_states_corr(tmp_idx,4)+half_win3-1);

    tmp_labels=temp_labels(table_states(tmp_idx,4)-half_win3:table_states(tmp_idx,4)+half_win3-1);
    spike_freq_2to3_2(:,:,i)=tmp_spike_freq;
    labels_2to3_2=tmp_labels;
end

% predict probability curve by all neurons at corrected trans time points
temp_data=spike_freq_2to3_2;

acc_temp=[];
for t=1:size(temp_data,3)
    %progressbar(t,size(temp_data,3))
    tmp_br_data=squeeze(temp_data(:,:,t));
    parfor f =1:numFolds
        temp_svm=SVM_brain{f};
        [pred_state,pred_score] = predict(temp_svm,tmp_br_data');
        acc=length(find(pred_state-labels_2to3_2==0))/length(pred_state)*100;

        pred_state_2(:,t,f)=pred_state;
        pred_score_2(:,:,t,f)=pred_score;
        acc_temp(t,f)=acc;
    end
end
score_good_curve_corr=squeeze(mean(pred_score_2,4));
score_good_curve_corr=score_good_curve_corr(:,1,:);


for t = 1:size(score_good_curve_corr,3)
    figure('Color','white');
    plot(squeeze(score_good_curve_corr(:,1,t)),'LineWidth',1.5,'Color','k');
    xlabel('Time','FontSize',24,'FontName','Arial');
    ylabel('Score','FontSize',24,'FontName','Arial');
    set(gca,'FontSize',18,'FontName','Arial','XTick',[0 50 100 150 200],'XTickLabel',[-100 -50 0 50 100])
    hold on
    plot([0 200],[0.5 0.5],'--r','LineWidth',2)
    box off
end
%% part 3 GPR bondary finding
% use GPR for seeking the bondary of seq
temp_spike_freq_slid_3=movmean(temp_spike_freq,25,2);    % sliding win = 0.625 s  
num_neurons=size(temp_spike_freq_slid_3,1);
trial_num=length(trans_time);

freq_win=50;
win_center=[-200:1:200];
validationRMSE=[];
test_RMSE=[];
parfor i = 1:length(win_center)
    neuron_trans_freq=zeros(num_neurons,2*freq_win,trial_num);
    for t = 1:trial_num
        tmp_idx=table_states_corr(idx_medium23_good_curve(t)+1,4);
        neuron_trans_freq(:,:,t)=temp_spike_freq_slid_3(:,tmp_idx+win_center(i)-freq_win:tmp_idx+win_center(i)+freq_win-1);
    end

    t_offsets_label=1:2*freq_win;
    t_offsets=repmat(t_offsets_label,1,trial_num);
    tmp_data=zscore(neuron_trans_freq(:,:,:),0,2);
    tmp_data=reshape(tmp_data(:,:,:),num_neurons,[]);
    data=[tmp_data;t_offsets];

    [trainedModel, validationRMSE(i)] = trainRegressionModel(data);

    %averaged trials
    test=zscore(mean(neuron_trans_freq,3),0,2);
    yfit = trainedModel.predictFcn(test);
    test_RMSE(i)=sqrt(sum((yfit-t_offsets_label').^2)/length(t_offsets_label));
end

figure('Color','white');
plot(test_RMSE(:),'-k','LineWidth',3);
xlabel('Position of window center','FontSize',24,'FontName','Arial');
ylabel('Predicted time labels','FontSize',24,'FontName','Arial');
xticks([0 100 200 300 400]);
xticklabels([-200 -100 0 100 200]);
xlim([0 400]);
set(gca,'FontSize',18,'FontName','Arial')
ylim([10 90]);
box off


left_win=80; % according to RMSE curve
right_win=-5;
test_RMSE_win_boundary=test_RMSE;

%% part 4 identify sequence neurons
% by peak entropy 

averaged_freq=[];
cluster_channel_br=[];
cluster_channel_br_all=[];
cluster_channel_name={};
cluster_channel_name_all={};
PE_p_value_all=[];
pos_re_trans=[];


% PE calculate
temp_spike_freq_slid_3=movmean(temp_spike_freq,25,2);  %......................
neuron_trans_freq=zeros(size(temp_spike_freq_slid_3,1),left_win+right_win,length(idx_medium23_good_curve));
for t = 1:length(idx_medium23_good_curve)
    tmp_idx=table_states_corr(idx_medium23_good_curve(t)+1,4);
    neuron_trans_freq(:,:,t)=temp_spike_freq_slid_3(:,tmp_idx-left_win:tmp_idx+right_win-1);
end

% find fixed peak pattern
fluc_trial=squeeze(mean(abs(zscore(neuron_trans_freq(:,:,:),0,2)),2));
presence_ratio_t=0.5;
trial_num_t=floor(presence_ratio_t*length(idx_medium23_good_curve));
high_presence_neuron=find(sum(fluc_trial==0,2)<=trial_num_t);

tmp_data=neuron_trans_freq(:,:,:); 
[~,pos_max] = max(tmp_data(:,:,:),[],2);
pos_max=squeeze(pos_max);

peak_m=zeros(size(tmp_data,1),size(tmp_data,3),size(tmp_data,2));
for k = 1:size(tmp_data,3)
    for j = 1:size(tmp_data,1)
        peak_m(j,k,pos_max(j,k))=1;
    end
end
PE= SeqIndexDB(peak_m,15);

% Bootstrap for PE distribution of each neuron
num_trials=length(idx_medium23_good_curve);
PE_bootstrap=[];
parfor sample_num=1:10000
    randomOrder=randperm(size(temp_spike_freq_slid_3,2)-(left_win+right_win),num_trials)+left_win; % avoid boundary cases
    pseudo_trial_freq=zeros(size(temp_spike_freq_slid_3,1),left_win+right_win,num_trials);
    for m = 1:num_trials
        pseudo_trial_freq(:,:,m)=temp_spike_freq_slid_3(:,randomOrder(m)-left_win:randomOrder(m)+right_win-1);
    end
    
    tmp_data=pseudo_trial_freq(:,:,:); 
    [~,pos_max] = max(tmp_data(:,:,:),[],2);
    pos_max=squeeze(pos_max);
    
    peak_m=zeros(size(tmp_data,1),size(tmp_data,3),size(tmp_data,2));
    for k = 1:size(tmp_data,3)
        for j = 1:size(tmp_data,1)
            peak_m(j,k,pos_max(j,k))=1;
        end
    end
    PE_bootstrap(:,sample_num)= SeqIndexDB(peak_m,15);
end

PE_threshold=[];
PE_p_value=[];
for j = 1:size(PE_bootstrap,1)
    [B_PE,~]=sort(PE_bootstrap(j,:),'descend');
    PE_threshold(1,j)=B_PE(3000);%30%
    PE_p_value(j)=sum(PE_bootstrap(j,:)>=PE(j))/10000;
end

stable_peak_neuron=find((PE-PE_threshold)>=0);
neuron_hp_sp=intersect(high_presence_neuron,stable_peak_neuron);

tmp_idx=find(tmp_cluster_channel_br(:,5)~=0);
tmp_idx=intersect(tmp_idx,neuron_hp_sp);

trans_tmp_idx=tmp_idx;
averaged_freq=mean(neuron_trans_freq(tmp_idx,:,:),3);
cluster_channel_br=tmp_cluster_channel_br(tmp_idx,:);
cluster_channel_br_all=tmp_cluster_channel_br;
cluster_channel_name=tmp_cluster_channel_name(:,tmp_idx);
cluster_channel_name_all=tmp_cluster_channel_name;
PE_p_value_all=PE_p_value;


% sorted according to averaged trial max peak 
%averaged_freq_z=zscore(mean(neruon_trans_freq_trans(a,:,:),3),0,2);
averaged_freq_z=zscore(averaged_freq,0,2);
[~,pos_max]=max((averaged_freq_z),[],2);
[B,I]=sort(pos_max,'ascend');
averaged_freq_sorted=averaged_freq_z(I,:);
I_trans=I;                                 % ...
B_trans=B;
neuron_trans_freq_trans=neuron_trans_freq; % ...
figure('Color','w');
imagesc(averaged_freq_sorted);
%colormap(slanCM('bwr'));
colormap(flipud(othercolor('RdBu9')));
clim([-2.5 2.5]);
%set(gca,'YDir','normal');
xlabel('Time bins','FontSize',18);
ylabel('Neurons','FontSize',18);
